1. 将二进制编码转换为整数。
2. 通过逆映射从整数还原到实数值。

我们将以下代码更新为包含解码的步骤并输出解码后的量测值 \( y_d \)。

```matlab
function [binaryCode, y_d, p, one_minus_p] = encode_decode_to_binary(y, a, L)
    % 检查y是否在[-a, a]范围内
    if y < -a || y > a
        error('y must be in the range [-a, a]');
    end

    % 计算区间D
    D = (2 * a) / (2^L - 1);

    % 计算c
    c = floor((y + a) / D);

    % 计算当前区间的边界值
    lower_bound = c * D - a;
    upper_bound = (c + 1) * D - a;

    % 判断y是等于cD还是(c+1)D
    if abs(y - lower_bound) < eps
        fprintf('y is exactly at cD where c = %d, cD = %f\n', c, lower_bound);
        p = 0;
        one_minus_p = 1;
    elseif abs(y - upper_bound) < eps
        fprintf('y is exactly at (c+1)D where c = %d, (c+1)D = %f\n', c, upper_bound);
        p = 1;
        one_minus_p = 0;
        c = c + 1; % 调整c值
    else
        % y在(cD, (c+1)D)之间的相对位置: 0 <= rel_pos < 1
        rel_pos = (y - lower_bound) / D;
        p = rel_pos;
        one_minus_p = 1 - rel_pos;
    end

    % 将y映射到[0, 2^L - 1]的整数值
    mappedValue = round((y + a) / D);

    % 将mappedValue转为二进制字符串，固定长度为L
    binaryCode = dec2bin(mappedValue, L);

    % 对编码后的值进行解码
    decodedValue = bin2dec(binaryCode);

    % 反映射到原区间 [-a, a]
    y_d = decodedValue * D - a;

    % Debug输出
    fprintf('Decoded value from binary is: %f\n', y_d);
